/// <summary>
/// A contract class for <c>DBMUpdateTableStatisticsService.process()</c> operation.
/// </summary>
///<remarks>
///</remarks>
[DataContractAttribute]
[SysOperationAlwaysInitialize]
public class DBMUpdateTableStatisticsContract implements SysOperationInitializable,SysOperationValidatable
{
    private Set tables;    
    private DBMStatSamplingMode samplingMode;
    private DBMStatSamplingScope samplingScope;
    private int64 sampleSize;
}

Method.Source:
[DataMember,  SysOperationLabel("@DBMUpdateTableStats:ListOfTablesLabel"),
    SysOperationHelpText("@DBMUpdateTableStats:ListOfTablesHelp"),
    AifCollectionTypeAttribute("_tables", Types::String),
    AifCollectionTypeAttribute("return", Types::String)]
public Set parmTables(Set _tables = tables)
{
    tables = _tables;
    return tables;
}

public DBMStatSamplingMode parmSamplingMode(DBMStatSamplingMode _samplingMode = samplingMode)
{
    samplingMode = _samplingMode;
    return samplingMode;
}

public DBMStatSamplingScope parmSamplingScope(DBMStatSamplingScope _samplingScope = samplingScope)
{
    samplingScope = _samplingScope;
    return samplingScope;
}

public int64 parmSampleSize(int64 _sampleSize = sampleSize)
{
    if (samplingScope == DBMStatSamplingScope::Percent && _sampleSize>100)
    {
        _sampleSize = 100;
    }
    sampleSize = _sampleSize;
    return sampleSize;
}

public void initialize()
{
    tables = new Set(Types::String);
}

public boolean validate()
{
    boolean ret=true;
    if (ret && (tables.elements() == 0))
    {
        ret = checkFailed("@DBMUpdateTableStats:TableListIsEmpty");
    }
    return ret;
}
